  1→/**
  2→ * belt init command
  3→ *
  4→ * Initialize a new monorepo with full harness.
  5→ * Creates complete project structure with:
  6→ * - Monorepo configuration (package.json, turbo.json, tsconfig)
  7→ * - .belt/ directory with harness
  8→ * - .claude/ directory with hooks
  9→ * - Restrictive CLAUDE.md
 10→ * - Git initialization
 11→ */
 12→
 13→import { existsSync, mkdirSync, readdirSync, writeFileSync } from 'fs';
 14→import { basename, join, resolve } from 'path';
 15→import {
 16→  createFeaturesFile,
 17→  createProgressFile,
 18→  initBeltDirectory,
 19→} from '../harness/persistence/progress';
 20→import { AGENTRC_TEMPLATE } from '../templates/agentrc';
 21→import { generateClaudeMd } from '../templates/claude-md';
 22→import {
 23→  BIOME_JSON,
 24→  GITIGNORE,
 25→  ROOT_PACKAGE_JSON,
 26→  ROOT_TSCONFIG,
 27→  TURBO_JSON,
 28→} from '../templates/monorepo';
 29→import { checkBun, ensureBun } from '../utils/bun-installer';
 30→import { createInitialCommit, initGit, isGitRepo } from '../utils/git';
 31→import { checkOllama } from '../utils/ollama-installer';
 32→import { setup as beltSetup } from './setup';
 33→
 34→export interface InitOptions {
 35→  skipBunCheck?: boolean;
 36→  skipOllamaCheck?: boolean;
 37→  skipGit?: boolean;
 38→  skipBrainstorm?: boolean;
 39→}
 40→
 41→export async function init(
 42→  targetDir: string,
 43→  options: InitOptions = {},
 44→): Promise<void> {
 45→  const projectDir = resolve(targetDir);
 46→  const projectName = basename(projectDir);
 47→
 48→  console.log('\n🚀 belt init');
 49→  console.log(`   Target: ${projectDir}`);
 50→  console.log(`   Project: ${projectName}\n`);
 51→
 52→  // Create directory if needed
 53→  if (!existsSync(projectDir)) {
 54→    mkdirSync(projectDir, { recursive: true });
 55→    console.log(`✅ Created directory: ${projectDir}`);
 56→  }
 57→
 58→  // Check if directory is empty
 59→  const files = readdirSync(projectDir).filter(f => !f.startsWith('.'));
 60→  if (files.length > 0) {
 61→    console.log('⚠️  Directory is not empty. Proceeding with setup only.');
 62→    console.log(
 63→      '   Use belt init on an empty directory for full scaffolding.\n',
 64→    );
 65→    await beltSetup(projectDir);
 66→    return;
 67→  }
 68→
 69→  // Step 1: Check prerequisites
 70→  console.log('📋 Checking prerequisites...\n');
 71→
 72→  if (!options.skipBunCheck) {
 73→    if (checkBun()) {
 74→      console.log('✅ Bun is installed');
 75→    } else {
 76→      console.log('⚠️  Bun is not installed');
 77→      console.log('   Installing bun...\n');
 78→      await ensureBun();
 79→    }
 80→  }
 81→
 82→  if (!options.skipOllamaCheck) {
 83→    if (checkOllama()) {
 84→      console.log('✅ Ollama is installed');
 85→      console.log('   Note: Use "ollama pull" to get required models:');
 86→      console.log('   - phi4-mini-reasoning (router)');
 87→      console.log('   - deepseek-r1:8b (reasoning)');
 88→      console.log('   - qwen2.5-coder:7b (code)\n');
 89→    } else {
 90→      console.log('⚠️  Ollama is not installed');
 91→      console.log('   Install from: https://ollama.ai/download');
 92→      console.log('   Continuing without harness LLM features...\n');
 93→    }
 94→  }
 95→
 96→  // Step 2: Create monorepo structure
 97→  console.log('📦 Creating monorepo structure...\n');
 98→
 99→  // packages/
100→  const packagesDir = join(projectDir, 'packages');
101→  mkdirSync(packagesDir, { recursive: true });
102→  console.log('✅ Created packages/');
103→
104→  // package.json
105→  const pkgJsonPath = join(projectDir, 'package.json');
106→  writeFileSync(
107→    pkgJsonPath,
108→    JSON.stringify(ROOT_PACKAGE_JSON(projectName), null, 2) + '\n',
109→  );
110→  console.log('✅ Created package.json');
111→
112→  // turbo.json
113→  const turboPath = join(projectDir, 'turbo.json');
114→  writeFileSync(turboPath, JSON.stringify(TURBO_JSON, null, 2) + '\n');
115→  console.log('✅ Created turbo.json');
116→
117→  // tsconfig.json
118→  const tsconfigPath = join(projectDir, 'tsconfig.json');
119→  writeFileSync(tsconfigPath, JSON.stringify(ROOT_TSCONFIG, null, 2) + '\n');
120→  console.log('✅ Created tsconfig.json');
121→
122→  // biome.json
123→  const biomePath = join(projectDir, 'biome.json');
124→  writeFileSync(biomePath, JSON.stringify(BIOME_JSON, null, 2) + '\n');
125→  console.log('✅ Created biome.json');
126→
127→  // .gitignore
128→  const gitignorePath = join(projectDir, '.gitignore');
129→  writeFileSync(gitignorePath, GITIGNORE);
130→  console.log('✅ Created .gitignore');
131→
132→  // Step 3: Create .belt directory
133→  console.log('\n📁 Creating .belt directory...\n');
134→  initBeltDirectory(projectDir);
135→  console.log('✅ Created .belt/');
136→  console.log('✅ Created .belt/harness/');
137→  console.log('✅ Created .belt/config/');
138→  console.log('✅ Created .belt/temp/');
139→
140→  // Create progress and features files
141→  createProgressFile(projectDir);
142→  console.log('✅ Created .belt/harness/progress.txt');
143→
144→  createFeaturesFile(projectDir, projectName);
145→  console.log('✅ Created .belt/harness/features.json');
146→
147→  // Step 4: Create CLAUDE.md
148→  console.log('\n📝 Creating CLAUDE.md...\n');
149→  const claudeMdPath = join(projectDir, 'CLAUDE.md');
150→  writeFileSync(claudeMdPath, generateClaudeMd(projectName));
151→  console.log('✅ Created CLAUDE.md (restrictive)');
152→
153→  // Step 5: Create .agentrc.ts
154→  const agentrcPath = join(projectDir, '.agentrc.ts');
155→  writeFileSync(agentrcPath, AGENTRC_TEMPLATE);
156→  console.log('✅ Created .agentrc.ts');
157→
158→  // Step 6: Create .claude directory with hooks
159→  console.log('\n🔧 Creating .claude directory...\n');
160→  const claudeDir = join(projectDir, '.claude');
161→  mkdirSync(claudeDir, { recursive: true });
162→
163→  const settingsJson = {
164→    $schema: 'https://json.schemastore.org/claude-code-settings.json',
165→    hooks: {
166→      PreToolUse: [
167→        {
168→          matcher: 'Write',
169→          hooks: [
170→            {
171→              type: 'command',
172→              command: 'bunx @belt/cli hook',
173→            },
174→          ],
175→        },
176→        {
177→          matcher: 'Edit',
178→          hooks: [
179→            {
180→              type: 'command',
181→              command: 'bunx @belt/cli hook',
182→            },
183→          ],
184→        },
185→      ],
186→    },
187→  };
188→
189→  const settingsPath = join(claudeDir, 'settings.json');
190→  writeFileSync(settingsPath, JSON.stringify(settingsJson, null, 2) + '\n');
191→  console.log('✅ Created .claude/');
192→  console.log('✅ Created .claude/settings.json');
193→
194→  // Step 7: Initialize git
195→  if (!options.skipGit) {
196→    console.log('\n📁 Initializing git...\n');
197→    if (!isGitRepo(projectDir)) {
198→      initGit(projectDir);
199→      createInitialCommit(projectDir, 'Initial commit - Belt monorepo setup');
200→    } else {
201→      console.log('ℹ️  Git repository already exists');
202→    }
203→  }
204→
205→  // Step 8: Summary
206→  console.log('\n' + '='.repeat(60));
207→  console.log('✨ Belt init complete!');
208→  console.log('='.repeat(60));
209→
210→  console.log(`
211→Project "${projectName}" has been created with:
212→
213→📁 Structure:
214→  ├── packages/           # Monorepo packages
215→  ├── .belt/              # Belt harness
216→  │   ├── harness/        # Session state
217→  │   ├── config/         # Future configs
218→  │   └── temp/           # Gitignored temp
219→  ├── .claude/            # Claude Code hooks
220→  ├── CLAUDE.md           # AI instructions (restrictive)
221→  ├── .agentrc.ts         # Agent rules
222→  ├── package.json        # Monorepo config
223→  ├── turbo.json          # Turborepo config
224→  ├── tsconfig.json       # TypeScript config
225→  └── biome.json          # Linter config
226→
227→📋 Next steps:
228→  1. cd ${projectName}
229→  2. bun install
230→  3. Create your first package in packages/
231→  4. Start coding with Claude Code!
232→
233→💡 Tips:
234→  - Read .belt/harness/progress.txt at each session
235→  - Update progress after completing tasks
236→  - Features are tracked in .belt/harness/features.json
237→  - CLAUDE.md contains strict rules for AI assistance
238→
239→🧠 Harness (optional):
240→  - Install Ollama: https://ollama.ai/download
241→  - Pull models: ollama pull phi4-mini-reasoning
242→  - Run brainstorming: belt brainstorm (coming soon)
243→`);
244→}
