  1→/**
  2→ * belt hook command
  3→ *
  4→ * Hook runner for Claude Code.
  5→ * Reads tool input from stdin and evaluates .agentrc.ts rules.
  6→ *
  7→ * This is a thin wrapper around @belt/ai hook-runner.
  8→ */
  9→
 10→import type {
 11→  AgentConfig,
 12→  AgentHookContext,
 13→  AgentRule,
 14→  RuleContext,
 15→} from '@belt/ai';
 16→import { existsSync } from 'fs';
 17→import { dirname, isAbsolute, relative, resolve } from 'path';
 18→
 19→/**
 20→ * Check if a path is safely within the project root.
 21→ * Uses path.relative() to prevent path traversal attacks.
 22→ */
 23→function isWithinProject(targetPath: string, projectRoot: string): boolean {
 24→  const resolvedTarget = resolve(targetPath);
 25→  const resolvedRoot = resolve(projectRoot);
 26→  const relativePath = relative(resolvedRoot, resolvedTarget);
 27→
 28→  // Path is outside project if:
 29→  // 1. relative path starts with '..' (trying to escape up)
 30→  // 2. relative path is absolute (different root/drive)
 31→  return !relativePath.startsWith('..') && !isAbsolute(relativePath);
 32→}
 33→
 34→const DEBUG = process.env.BELT_DEBUG === '1';
 35→const DEBUG_LOG = '/tmp/belt-hook-debug.log';
 36→const PROJECT_ROOT = process.env.CLAUDE_PROJECT_DIR || process.cwd();
 37→const AGENTRC_FILES = [
 38→  '.agentrc.ts',
 39→  'agentrc.ts',
 40→  '.agentrc.js',
 41→  'agentrc.js',
 42→];
 43→
 44→async function logDebug(message: string): Promise<void> {
 45→  if (!DEBUG) return;
 46→
 47→  const timestamp = new Date().toISOString();
 48→  const line = `[${timestamp}] ${message}\n`;
 49→
 50→  const { appendFileSync } = await import('fs');
 51→  appendFileSync(DEBUG_LOG, line);
 52→}
 53→
 54→async function readStdin(): Promise<string> {
 55→  return new Promise((resolve, reject) => {
 56→    let data = '';
 57→    process.stdin.setEncoding('utf8');
 58→    process.stdin.on('data', chunk => (data += chunk));
 59→    process.stdin.on('end', () => resolve(data));
 60→    process.stdin.on('error', reject);
 61→  });
 62→}
 63→
 64→async function findAgentrcFiles(startDir: string): Promise<string[]> {
 65→  const files: string[] = [];
 66→  let currentDir = resolve(startDir);
 67→
 68→  // Use isWithinProject for safe path traversal check
 69→  while (
 70→    isWithinProject(currentDir, PROJECT_ROOT) &&
 71→    currentDir !== '/' &&
 72→    currentDir.length >= PROJECT_ROOT.length
 73→  ) {
 74→    for (const filename of AGENTRC_FILES) {
 75→      const filePath = resolve(currentDir, filename);
 76→      if (existsSync(filePath) && isWithinProject(filePath, PROJECT_ROOT)) {
 77→        files.push(filePath);
 78→        break;
 79→      }
 80→    }
 81→    const parent = dirname(currentDir);
 82→    if (parent === currentDir) break;
 83→    currentDir = parent;
 84→  }
 85→
 86→  return files.reverse();
 87→}
 88→
 89→async function loadAndMergeConfigs(files: string[]): Promise<AgentConfig> {
 90→  let mergedConfig: AgentConfig = {
 91→    rules: [],
 92→    hooks: {},
 93→  };
 94→
 95→  for (const file of files) {
 96→    try {
 97→      await logDebug(`Loading: ${file}`);
 98→      const module = await import(file);
 99→      const config: AgentConfig = module.default || module;
100→
101→      if (typeof config.extend === 'function') {
102→        mergedConfig = config.extend(mergedConfig);
103→      } else {
104→        if (config.rules) {
105→          mergedConfig.rules = [
106→            ...(mergedConfig.rules || []),
107→            ...config.rules,
108→          ];
109→        }
110→        if (config.hooks) {
111→          mergedConfig.hooks = {
112→            ...mergedConfig.hooks,
113→            ...config.hooks,
114→          };
115→        }
116→      }
117→    } catch (err) {
118→      await logDebug(`Error loading ${file}: ${err}`);
119→    }
120→  }
121→
122→  return mergedConfig;
123→}
124→
125→async function evaluateRuleMatch(
126→  rule: AgentRule,
127→  filePath: string,
128→  ctx: RuleContext,
129→): Promise<boolean> {
130→  const { match } = rule;
131→
132→  if (typeof match === 'string') return filePath.includes(match);
133→  if (match instanceof RegExp) return match.test(filePath);
134→  if (typeof match === 'function') return await match(filePath, ctx);
135→
136→  return false;
137→}
138→
139→export async function hook(): Promise<void> {
140→  await logDebug('=== BELT HOOK START ===');
141→
142→  let stdinJson: string;
143→  try {
144→    stdinJson = await readStdin();
145→    await logDebug(`STDIN: ${stdinJson.substring(0, 200)}...`);
146→  } catch {
147→    process.exit(0);
148→  }
149→
150→  let toolName: string;
151→  let toolInput: Record<string, unknown>;
152→  let filePath: string | undefined;
153→
154→  try {
155→    const parsed = JSON.parse(stdinJson);
156→    toolName = parsed.tool_name || 'unknown';
157→    toolInput = parsed.tool_input || {};
158→    filePath = toolInput.file_path as string | undefined;
159→  } catch {
160→    process.exit(0);
161→  }
162→
163→  await logDebug(`Tool: ${toolName}, FilePath: ${filePath || 'none'}`);
164→
165→  if (!filePath) {
166→    process.exit(0);
167→  }
168→
169→  // Validate filePath is within project to prevent path traversal
170→  if (!isWithinProject(filePath, PROJECT_ROOT)) {
171→    await logDebug(`BLOCKED: Path outside project root: ${filePath}`);
172→    console.error(`\n❌ Security: File path outside project root`);
173→    process.exit(2);
174→  }
175→
176→  const targetDir = dirname(filePath);
177→  const agentrcFiles = await findAgentrcFiles(targetDir);
178→  await logDebug(`Found ${agentrcFiles.length} agentrc files`);
179→
180→  if (agentrcFiles.length === 0) {
181→    process.exit(0);
182→  }
183→
184→  const config = await loadAndMergeConfigs(agentrcFiles);
185→
186→  const ruleCtx: RuleContext = {
187→    tool: toolName,
188→    input: toolInput,
189→    projectRoot: PROJECT_ROOT,
190→  };
191→
192→  for (const rule of config.rules || []) {
193→    const matches = await evaluateRuleMatch(rule, filePath, ruleCtx);
194→
195→    if (matches) {
196→      await logDebug(`Rule ${rule.id} matched: ${rule.action}`);
197→
198→      if (rule.action === 'block') {
199→        console.error(`\n❌ RULE VIOLATION: ${rule.id}`);
200→        console.error(`   ${rule.message || 'Action blocked'}`);
201→        console.error(`   File: ${filePath}\n`);
202→        process.exit(2);
203→      }
204→
205→      if (rule.action === 'warn') {
206→        console.error(`\n⚠️  WARNING: ${rule.id}`);
207→        console.error(`   ${rule.message || 'Warning'}\n`);
208→      }
209→    }
210→  }
211→
212→  if (config.hooks?.PreToolUse) {
213→    let blocked = false;
214→    let blockMessage = '';
215→    const injectedContent: string[] = [];
216→
217→    const hookCtx: AgentHookContext = {
218→      tool: toolName,
219→      input: toolInput,
220→      projectRoot: PROJECT_ROOT,
221→      filePath,
222→      block: (msg: string) => {
223→        blocked = true;
224→        blockMessage = msg;
225→      },
226→      warn: (msg: string) => console.error(`⚠️  ${msg}`),
227→      inject: (content: string) => injectedContent.push(content),
228→    };
229→
230→    try {
