  2→ * Brainstorm Command
  3→ *
  4→ * Runs the AI-powered brainstorming session using local LLMs.
  5→ * Implements Self-MoA, Self-Refine, and LLM-as-Judge patterns.
  6→ */
  7→
  8→import { existsSync } from 'fs';
  9→import { resolve } from 'path';
 10→import {
 11→  createBrainstormSession,
 12→  type BrainstormSessionConfig,
 13→  type FeatureBacklog,
 14→  type ProjectContext,
 15→} from '../harness/brainstorm';
