 70→/**
 71→ * Detect optimal download concurrency based on system resources
 72→ */
 73→export function detectOptimalConcurrency(): {
 74→  concurrency: number;
 75→  reason: string;
 76→} {
 77→  const cpuCount = os.cpus().length;
 78→  const freeMemoryGB = os.freemem() / 1024 ** 3;
 79→  const totalMemoryGB = os.totalmem() / 1024 ** 3;
 80→
 81→  // Each ~5GB model needs ~2GB buffer during download
 82→  const memoryBasedLimit = Math.floor(freeMemoryGB / 2);
 83→  const cpuBasedLimit = Math.min(cpuCount, 4);
 84→
 85→  const optimal = Math.max(1, Math.min(memoryBasedLimit, cpuBasedLimit, 4));
 86→
 87→  return {
 88→    concurrency: optimal,
 89→    reason: `CPU: ${cpuCount} cores, RAM: ${freeMemoryGB.toFixed(1)}GB free / ${totalMemoryGB.toFixed(1)}GB total → ${optimal} parallel downloads`,
 90→  };
 91→}
