124→export function formatBytes(bytes: number): string {
125→  if (bytes === 0) return '0 B';
126→  const k = 1024;
127→  const sizes = [
128→    'B',
129→    'KB',
130→    'MB',
131→    'GB',
132→    'TB',
133→  ];
134→  const i = Math.floor(Math.log(bytes) / Math.log(k));
135→  return `${(bytes / Math.pow(k, i)).toFixed(1)} ${sizes[i]}`;
136→}
